module RefModule (
    input clk,
    input [7:0] data_in,
    output reg [3:0] count
);

    integer i;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        count = 4'b0;
        for (i = 0; i < 8; i = i + 1) begin
            if (data_in[i]) count = count + 1;
        end
    end
endmodule
